56	using namespace cutlass::fmha::kernel;
57	using namespace cutlass::fmha::collective;
58	using namespace cutlass::fmha;
59	using namespace cutlass;
60	
61	
62	template<
63	  class DType,
64	  bool kIsVarlen,
65	  bool kIsMla,
66	  class TileShape,
67	  class ActiveMask
68	>
69	struct BwdRunner {
70	
71	  using Element = DType;
72	  using ElementAccumulator = float;
73	
74	  // Q K D D_VO (H B)
75	  using ProblemShape = std::conditional_t<
76	    kIsVarlen,
77	    cute::tuple<VariableLength, VariableLength, int, int, cute::tuple<int, int>>,
78	    cute::tuple<int, int, int, int, cute::tuple<int, int>>
79	  >;
80	
81	  using Operation = cutlass::fmha::device::Sm100FmhaBwd<ProblemShape, Element, ElementAccumulator, TileShape, kIsMla, ActiveMask>;
82	  
83	  using TensorStride = Stride<int, _1, Stride<int, int>>; 
84	  using StrideQ = TensorStride;                               // Seq DQK (H B)
85	  using StrideK = TensorStride;                               // Seq DQK (H B)
86	  using StrideV = TensorStride;                               // Seq DVO (H B)
87	  using StrideO = TensorStride;                               // Seq DVO (H B)
88	  using StrideLSE = Stride<_1, Stride<int, int>>;             // Seq (H B)
89	
90	  // Backwards specific
91	  using StrideDQ = TensorStride;
92	  using StrideDK = TensorStride;                              // Seq DQK (H B)
93	  using StrideDV = TensorStride;                              // Seq DVO (H B)
94	  using StrideDO = TensorStride;
95	
96	  static void run(at::Tensor workspace_buffer, at::Tensor d_o, at::Tensor q, at::Tensor k,
97	                  at::Tensor v, at::Tensor o, at::Tensor lse,
98	                  at::Tensor cumulative_seqlen_q, at::Tensor cumulative_seqlen_kv,
99	                  at::Tensor dq, at::Tensor dk, at::Tensor dv,
100	                  float softmax_scale, int max_seqlen_q, int max_seqlen_kv) {
101	    const at::cuda::CUDAGuard device_guard{(char)q.get_device()};
102	    const int device_id = q.get_device();
103	
104	    cutlass::KernelHardwareInfo hw_info;
105	    hw_info.device_id =device_id;
106	    hw_info.sm_count = cutlass::KernelHardwareInfo::query_device_multiprocessor_count(hw_info.device_id);
107	    ProblemShape problem_shape;
108	    cute::tuple<int, int, int, int, cute::tuple<int, int>> tensor_shape;
109	
110	
111	    int d = q.size(-1);
112	    int d_vo = v.size(-1);
113	    int batch_size = cumulative_seqlen_q.size(0) - 1;
114	    int num_qo_heads = q.size(1);
115	    int total_seqlen_q = q.size(0);
116	    int total_seqlen_kv = k.size(0);
117	    
118	    //varlen: q: [Q, H, D]
119	    //fixedlen: q: [B, H, Q, D] 
120	    if constexpr (kIsVarlen) {
121	      problem_shape = cute::make_tuple(
122	        VariableLength{max_seqlen_q, static_cast<int*>(cumulative_seqlen_q.data_ptr()), total_seqlen_q},
123	        VariableLength{max_seqlen_kv, static_cast<int*>(cumulative_seqlen_kv.data_ptr()), total_seqlen_kv},
124	        d, d_vo, cute::make_tuple(num_qo_heads, batch_size));
125	      tensor_shape = make_shape(total_seqlen_q, total_seqlen_kv, d, d_vo, make_shape(num_qo_heads, 1));
126	    } else {
127	      int q_len = total_seqlen_q / batch_size;
128	      int kv_len = total_seqlen_kv / batch_size;
129	      problem_shape = cute::make_tuple(q_len, kv_len, d, d_vo, cute::make_tuple(num_qo_heads, batch_size));
130	      tensor_shape = problem_shape;
131	    }
132	
133	    auto [Q, K, D, D_VO, HB] = tensor_shape;
134	    auto [H, B] = HB;
135	
136	    int q_stride0 = q.stride(0), q_stride1 = q.stride(1), q_stride2 = q.stride(2);
137	    int k_stride0 = k.stride(0), k_stride1 = k.stride(1), k_stride2 = k.stride(2);
138	    int v_stride0 = v.stride(0), v_stride1 = v.stride(1), v_stride2 = v.stride(2);
139	    int o_stride0 = o.stride(0), o_stride1 = o.stride(1), o_stride2 = o.stride(2);
140	    int lse_stride0 = lse.stride(0), lse_stride1 = lse.stride(1);
141	    int dq_stride0 = dq.stride(0), dq_stride1 = dq.stride(1), dq_stride2 = dq.stride(2);
142	    int dk_stride0 = dk.stride(0), dk_stride1 = dk.stride(1), dk_stride2 = dk.stride(2);
143	    int dv_stride0 = dv.stride(0), dv_stride1 = dv.stride(1), dv_stride2 = dv.stride(2);
144	    int do_stride0 = d_o.stride(0), do_stride1 = d_o.stride(1), do_stride2 = d_o.stride(2);
145	    TORCH_CHECK(q_stride2 == 1);
146	    TORCH_CHECK(k_stride2 == 1);
147	    TORCH_CHECK(v_stride2 == 1);
148	    TORCH_CHECK(o_stride2 == 1);
149	    TORCH_CHECK(lse_stride0 == 1);
150	    TORCH_CHECK(dq_stride2 == 1);
151	    TORCH_CHECK(dk_stride2 == 1);
152	    TORCH_CHECK(dv_stride2 == 1);
153	    TORCH_CHECK(do_stride2 == 1);
154	
155	    StrideQ stride_Q = make_stride(q_stride0, _1{}, make_stride(q_stride1, B == 1 ? 0 : q_stride0*Q));
156	    StrideK stride_K = make_stride(k_stride0, _1{}, make_stride(k_stride1, B == 1 ? 0 : k_stride0*K));
157	    StrideV stride_V = make_stride(v_stride0, _1{}, make_stride(v_stride1, B == 1 ? 0 : v_stride0*K));
158	    StrideO stride_O = make_stride(o_stride0, _1{}, make_stride(o_stride1, B == 1 ? 0 : o_stride0*Q));
159	    StrideLSE stride_LSE = make_stride(_1{}, make_stride(lse_stride1, B == 1 ? 0 : Q));
160	
161	    StrideDQ stride_dQ = make_stride(dq_stride0, _1{}, make_stride(dq_stride1, B == 1 ? 0 : dq_stride0*Q));
162	    StrideDK stride_dK = make_stride(dk_stride0, _1{}, make_stride(dk_stride1, B == 1 ? 0 : dk_stride0*K));
163	    StrideDV stride_dV = make_stride(dv_stride0, _1{}, make_stride(dv_stride1, B == 1 ? 0 : dv_stride0*K));
164	    StrideDO stride_dO = make_stride(do_stride0, _1{}, make_stride(do_stride1, B == 1 ? 0 : do_stride0*Q));
165	
166	    typename Operation::Arguments arguments{
167	      problem_shape,
168	      (static_cast<Element*>(q.data_ptr())), stride_Q,
169	      (static_cast<Element*>(k.data_ptr())), stride_K,
170	      (static_cast<Element*>(v.data_ptr())), stride_V,
171	      (static_cast<Element*>(o.data_ptr())), stride_O,
172	      (static_cast<ElementAccumulator*>(lse.data_ptr())), stride_LSE,
173	      (static_cast<Element*>(d_o.data_ptr())), stride_dO,
174	      (static_cast<Element*>(dq.data_ptr())), stride_dQ,
175	      (static_cast<Element*>(dk.data_ptr())), stride_dK,
176	      (static_cast<Element*>(dv.data_ptr())), stride_dV,
177	      static_cast<ElementAccumulator>(softmax_scale),
178	      hw_info
179	    };
180	
181	    Operation op;
182	
183	    uint8_t* workspace_ptr = static_cast<uint8_t*>(workspace_buffer.data_ptr());
184	
185	    CUTLASS_CHECK(op.can_implement(arguments));
186	    CUTLASS_CHECK(op.initialize(arguments, workspace_ptr));
187	    CUTLASS_CHECK(op.run(at::cuda::getCurrentCUDAStream()));
188	  }
189	
190	};
